array.string:
PLIST="$HOME/Library/LaunchAgents/com.openclaw.clawndom.plist" LOG="/usr/local/var/log/clawndom-refresh.log" log() { echo "$(date '+%Y-%m-%d %H:%M:%S') $1" >> "$LOG"; }
TOKEN=$(security find-generic-password -s "Claude Code-credentials" -w 2>/dev/null | python3 -c "import sys,json; print(json.load(sys.stdin)['claudeAiOauth']['accessToken'])" 2>/dev/null) if [ -z "$TOKEN" ]; then log "ERROR: Could not extract token" exit 1 fi
python3 -c " import plistlib with open('$PLIST', 'rb') as f: plist = plistlib.load(f) plist['EnvironmentVariables']['CLAUDE_CODE_OAUTH_TOKEN'] = '$TOKEN' with open('$PLIST', 'wb') as f: plistlib.dump(plist, f) " plutil -convert xml1 "$PLIST" launchctl unload "$PLIST" 2>/dev/null launchctl load "$PLIST" log "OK: Token refreshed and service reloaded"
